import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';
import { useAuth } from '../../context/AuthContext';

const CATEGORIES = ['Technology', 'Arts', 'Sports', 'Academic', 'Cultural', 'Business', 'Science', 'Social', 'Other'];

const CATEGORY_ICONS = {
  Technology: '💻', Arts: '🎨', Sports: '⚽', Academic: '📚',
  Cultural: '🎭', Business: '💼', Science: '🔬', Social: '🤝', Other: '🌟',
};
const getCategoryIcon = (cat) => CATEGORY_ICONS[cat] || '🏛️';

const EVENT_STATUS_COLOR = {
  published: '#10b981', pending_approval: '#f59e0b', rejected: '#ef4444',
  draft: '#6b7280', completed: 'var(--purple-light)', cancelled: '#6b7280',
};
const EVENT_STATUS_LABEL = {
  published: '✓ Published', pending_approval: '⏳ Pending', rejected: '❌ Rejected',
  draft: '📝 Draft', completed: '✅ Completed', cancelled: '🚫 Cancelled',
};

export default function CommunityAdminDashboard() {
  const { user } = useAuth();
  const [community, setCommunity]     = useState(null);
  const [events, setEvents]           = useState([]);
  const [joinRequests, setJoinRequests] = useState([]);
  const [loading, setLoading]         = useState(true);
  const [activeTab, setActiveTab]     = useState('overview');

  // Profile edit state
  const [form, setForm]               = useState({});
  const [saving, setSaving]           = useState(false);
  const [profileTab, setProfileTab]   = useState('edit'); // 'edit' | 'preview'

  const fetchData = async () => {
    setLoading(true);
    try {
      const communityRes = await api.get('/communities/my/profile');
      const c = communityRes.data.data;
      setCommunity(c);
      setForm({
        name: c.name, description: c.description, category: c.category,
        logo: c.logo || '', coverImage: c.coverImage || '',
        socialLinks: c.socialLinks || {},
      });
      const [eventsRes, requestsRes] = await Promise.all([
        api.get('/events/my-community'),
        api.get(`/communities/${c._id}/join-requests`),
      ]);
      setEvents(eventsRes.data.data || []);
      setJoinRequests(requestsRes.data.data || []);
    } catch {
      toast.error('Failed to load dashboard');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []);

  const set = (k, v) => setForm(p => ({ ...p, [k]: v }));
  const setSocial = (k, v) => setForm(p => ({ ...p, socialLinks: { ...p.socialLinks, [k]: v } }));

  const handleSave = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      await api.put(`/communities/${community._id}`, form);
      toast.success('Community profile updated!');
      // Refresh community data
      const res = await api.get('/communities/my/profile');
      setCommunity(res.data.data);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to update');
    } finally {
      setSaving(false);
    }
  };

  const handleJoinRequest = async (communityId, requestId, action, userName) => {
    try {
      await api.put(
        `/communities/${communityId}/join-requests/${requestId}/${action}`,
        action === 'reject' ? { reason: prompt('Reason (optional):') || '' } : {}
      );
      toast.success(`Request ${action}ed for ${userName}`);
      fetchData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed');
    }
  };

  if (loading) return (
    <div className="loading-screen" style={{ minHeight: '400px', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '16px' }}>
      <div className="spinner" style={{ width: '40px', height: '40px', borderWidth: '3px' }} />
      <span style={{ color: 'var(--text-secondary)' }}>Loading dashboard...</span>
    </div>
  );

  const tabs = [
    { id: 'overview',  label: 'Overview',    icon: '📊' },
    { id: 'requests',  label: `Join Requests${joinRequests.length > 0 ? ` (${joinRequests.length})` : ''}`, icon: '👋' },
    { id: 'events',    label: 'Events',       icon: '📅' },
    { id: 'community', label: 'Community',    icon: '🏛️' },
  ];

  return (
    <div className="page-wrapper" style={{ background: 'var(--bg-primary)', minHeight: '100vh' }}>
      <div className="container" style={{ maxWidth: 1200, margin: '0 auto', padding: '32px 20px' }}>

        {/* Header */}
        <div className="page-header" style={{ marginBottom: 32 }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: 16 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
              <div style={{ width: 48, height: 48, background: 'linear-gradient(135deg, var(--purple-primary), var(--cyan-accent))', borderRadius: 'var(--radius-md)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 24 }}>
                🏛️
              </div>
              <div>
                <h2 style={{ fontFamily: 'var(--font-display)', margin: 0, fontSize: '1.75rem' }}>
                  COMMUNITY <span className="gradient-text">DASHBOARD</span>
                </h2>
                <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', marginTop: 4 }}>
                  {community?.name} — Manage your community
                </p>
              </div>
            </div>
            <div style={{ display: 'flex', gap: 12 }}>
              <Link to="/community-admin/events" className="btn btn-primary" style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                <span>📅</span> Manage Events
              </Link>
              <Link to="/community-admin/members" className="btn btn-outline" style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                <span>👥</span> View Members
              </Link>
            </div>
          </div>
        </div>

        {/* Stats */}
        {community && (
          <div className="grid grid-4" style={{ marginBottom: 40, gap: 20 }}>
            {[
              { label: 'Total Members',    value: community.members?.length || 0, icon: '👥', color: 'var(--purple-light)', trend: 'All time',    bgGradient: 'linear-gradient(135deg, rgba(139,92,246,0.1), rgba(139,92,246,0.05))' },
              { label: 'Pending Requests', value: joinRequests.length,             icon: '⏳', color: 'var(--warning)',      trend: `${joinRequests.length} waiting`, bgGradient: 'linear-gradient(135deg, rgba(245,158,11,0.1), rgba(245,158,11,0.05))' },
              { label: 'Total Events',     value: events.length,                   icon: '📅', color: 'var(--cyan-accent)',  trend: 'All time',    bgGradient: 'linear-gradient(135deg, rgba(6,182,212,0.1), rgba(6,182,212,0.05))' },
              { label: 'Published Events', value: events.filter(e => e.status === 'published').length, icon: '🚀', color: '#10b981', trend: 'Active', bgGradient: 'linear-gradient(135deg, rgba(16,185,129,0.1), rgba(16,185,129,0.05))' },
            ].map((s, i) => (
              <div key={i} className="stat-card" style={{ background: s.bgGradient, border: '1px solid rgba(255,255,255,0.1)', transition: 'transform 0.2s', position: 'relative', overflow: 'hidden' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 16 }}>
                  <span style={{ fontSize: '2rem' }}>{s.icon}</span>
                  <span style={{ fontSize: '0.75rem', color: s.color, background: 'rgba(255,255,255,0.1)', padding: '4px 8px', borderRadius: 'var(--radius-sm)' }}>{s.trend}</span>
                </div>
                <div className="stat-value" style={{ color: s.color, fontSize: '2.5rem', fontWeight: 'bold' }}>{s.value}</div>
                <div className="stat-label" style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', marginTop: 8 }}>{s.label}</div>
              </div>
            ))}
          </div>
        )}

        {/* Tabs */}
        <div style={{ borderBottom: '1px solid rgba(255,255,255,0.1)', marginBottom: 32, display: 'flex', gap: 32 }}>
          {tabs.map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id)} style={{
              padding: '12px 0', background: 'none', border: 'none',
              color: activeTab === tab.id ? 'var(--purple-light)' : 'var(--text-muted)',
              cursor: 'pointer', fontSize: '0.9rem', fontWeight: activeTab === tab.id ? 600 : 400,
              borderBottom: activeTab === tab.id ? '2px solid var(--purple-light)' : '2px solid transparent',
              transition: 'all 0.2s', display: 'flex', alignItems: 'center', gap: 8,
            }}>
              <span>{tab.icon}</span> {tab.label}
            </button>
          ))}
        </div>

        {/* ── Overview Tab ── */}
        {activeTab === 'overview' && (
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 28 }}>

            {/* Join Requests */}
            <div>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
                <div>
                  <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem', margin: 0, display: 'flex', alignItems: 'center', gap: 8 }}>
                    <span>👋</span> Recent Join Requests
                    {joinRequests.length > 0 && (
                      <span style={{ background: 'var(--warning)', color: 'black', borderRadius: 100, padding: '2px 10px', fontSize: '0.7rem', fontWeight: 'bold' }}>
                        {joinRequests.length} pending
                      </span>
                    )}
                  </h3>
                  <p style={{ color: 'var(--text-muted)', fontSize: '0.75rem', marginTop: 4 }}>Review and manage membership requests</p>
                </div>
                <button onClick={() => setActiveTab('requests')} style={{ fontSize: '0.8rem', color: 'var(--purple-light)', background: 'none', border: 'none', cursor: 'pointer', fontWeight: 500 }}>View All →</button>
              </div>

              {joinRequests.length === 0 ? (
                <div className="card" style={{ textAlign: 'center', padding: '48px 24px' }}>
                  <div style={{ fontSize: '3rem', marginBottom: 16 }}>✅</div>
                  <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>No pending requests</div>
                  <div style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: 8 }}>All join requests have been processed</div>
                </div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                  {joinRequests.slice(0, 5).map(req => (
                    <div key={req._id} className="card" style={{ padding: 16 }}>
                      <div style={{ display: 'flex', alignItems: 'flex-start', gap: 12, marginBottom: 12 }}>
                        <div className="avatar" style={{ width: 40, height: 40, background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold' }}>
                          {req.user?.name?.charAt(0)}
                        </div>
                        <div style={{ flex: 1 }}>
                          <div style={{ fontWeight: 600, fontSize: '0.9rem', marginBottom: 2 }}>{req.user?.name}</div>
                          <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', fontFamily: 'var(--font-mono)' }}>{req.user?.itNumber}</div>
                        </div>
                        <span style={{ fontSize: '0.7rem', color: 'var(--warning)', background: 'rgba(245,158,11,0.1)', padding: '2px 8px', borderRadius: 'var(--radius-sm)' }}>Pending</span>
                      </div>
                      {req.message && (
                        <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', marginBottom: 12, fontStyle: 'italic', padding: 8, background: 'var(--bg-elevated)', borderRadius: 'var(--radius-sm)', borderLeft: '3px solid var(--purple-light)' }}>
                          "{req.message}"
                        </p>
                      )}
                      <div style={{ display: 'flex', gap: 8 }}>
                        <button onClick={() => handleJoinRequest(community._id, req._id, 'approve', req.user?.name)} className="btn btn-success btn-sm" style={{ flex: 1, justifyContent: 'center', background: 'linear-gradient(135deg, #10b981, #059669)', border: 'none' }}>✓ Approve</button>
                        <button onClick={() => handleJoinRequest(community._id, req._id, 'reject', req.user?.name)} className="btn btn-danger btn-sm" style={{ flex: 1, justifyContent: 'center', background: 'linear-gradient(135deg, #ef4444, #dc2626)', border: 'none' }}>✗ Reject</button>
                      </div>
                    </div>
                  ))}
                  {joinRequests.length > 5 && (
                    <button onClick={() => setActiveTab('requests')} style={{ textAlign: 'center', fontSize: '0.85rem', color: 'var(--purple-light)', padding: 12, background: 'none', border: 'none', cursor: 'pointer', fontWeight: 500 }}>
                      +{joinRequests.length - 5} more requests →
                    </button>
                  )}
                </div>
              )}
            </div>

            {/* Recent Events */}
            <div>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
                <div>
                  <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem', margin: 0, display: 'flex', alignItems: 'center', gap: 8 }}>
                    <span>📅</span> Recent Events
                  </h3>
                  <p style={{ color: 'var(--text-muted)', fontSize: '0.75rem', marginTop: 4 }}>Your upcoming and recent community events</p>
                </div>
                <Link to="/community-admin/events" style={{ fontSize: '0.8rem', color: 'var(--purple-light)', textDecoration: 'none', fontWeight: 500 }}>All Events →</Link>
              </div>

              {events.length === 0 ? (
                <div className="card" style={{ textAlign: 'center', padding: '48px 24px' }}>
                  <div style={{ fontSize: '3rem', marginBottom: 16 }}>📅</div>
                  <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', marginBottom: 8 }}>No events yet</div>
                  <Link to="/community-admin/events" className="btn btn-primary btn-sm" style={{ display: 'inline-flex', alignItems: 'center', gap: 8 }}>
                    <span>➕</span> Create Event
                  </Link>
                </div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                  {events.slice(0, 5).map(ev => (
                    <div key={ev._id} className="card" style={{ padding: 16, borderLeft: `3px solid ${EVENT_STATUS_COLOR[ev.status] || '#333'}` }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 8 }}>
                        <div style={{ fontWeight: 600, fontSize: '0.9rem' }}>{ev.title}</div>
                        <span style={{ background: `${EVENT_STATUS_COLOR[ev.status]}22`, color: EVENT_STATUS_COLOR[ev.status], border: `1px solid ${EVENT_STATUS_COLOR[ev.status]}44`, borderRadius: 100, padding: '2px 8px', fontSize: '0.68rem', fontWeight: 600, flexShrink: 0, marginLeft: 8 }}>
                          {EVENT_STATUS_LABEL[ev.status] || ev.status}
                        </span>
                      </div>
                      <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', display: 'flex', gap: 16 }}>
                        <span>📅 {new Date(ev.startDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}</span>
                        <span>👥 {ev.participants?.length || 0} registered</span>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        )}

        {/* ── Join Requests Tab ── */}
        {activeTab === 'requests' && (
          <div>
            <div style={{ marginBottom: 24 }}>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.3rem', marginBottom: 8 }}>All Join Requests</h3>
              <p style={{ color: 'var(--text-muted)' }}>Review and manage all membership requests</p>
            </div>
            {joinRequests.length === 0 ? (
              <div className="card" style={{ textAlign: 'center', padding: '64px 24px' }}>
                <div style={{ fontSize: '4rem', marginBottom: 16 }}>✅</div>
                <div style={{ fontSize: '1.1rem', marginBottom: 8 }}>No pending requests</div>
                <div style={{ color: 'var(--text-muted)' }}>All membership requests have been processed</div>
              </div>
            ) : (
              <div style={{ display: 'grid', gap: 16 }}>
                {joinRequests.map(req => (
                  <div key={req._id} className="card" style={{ padding: 20 }}>
                    <div style={{ display: 'flex', alignItems: 'flex-start', gap: 16 }}>
                      <div className="avatar" style={{ width: 48, height: 48, background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))', fontSize: '1.2rem', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                        {req.user?.name?.charAt(0)}
                      </div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontWeight: 600, fontSize: '1rem', marginBottom: 4 }}>{req.user?.name}</div>
                        <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: 8 }}>{req.user?.email} · {req.user?.itNumber}</div>
                        {req.message && (
                          <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: 16, padding: 12, background: 'var(--bg-elevated)', borderRadius: 'var(--radius-sm)', borderLeft: '3px solid var(--purple-light)' }}>
                            "{req.message}"
                          </p>
                        )}
                        <div style={{ display: 'flex', gap: 12 }}>
                          <button onClick={() => handleJoinRequest(community._id, req._id, 'approve', req.user?.name)} className="btn btn-success">✓ Approve</button>
                          <button onClick={() => handleJoinRequest(community._id, req._id, 'reject', req.user?.name)} className="btn btn-danger">✗ Reject</button>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* ── Events Tab ── */}
        {activeTab === 'events' && (
          <div>
            <div style={{ marginBottom: 24, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div>
                <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.3rem', marginBottom: 8 }}>Community Events</h3>
                <p style={{ color: 'var(--text-muted)' }}>Overview of all your community events</p>
              </div>
              <Link to="/community-admin/events" className="btn btn-primary" style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                📅 Manage Events
              </Link>
            </div>
            {events.length === 0 ? (
              <div className="card" style={{ textAlign: 'center', padding: '64px 24px' }}>
                <div style={{ fontSize: '4rem', marginBottom: 16 }}>📅</div>
                <div style={{ fontSize: '1.1rem', marginBottom: 8 }}>No events yet</div>
                <div style={{ color: 'var(--text-muted)', marginBottom: 24 }}>Create your first community event</div>
                <Link to="/community-admin/events" className="btn btn-primary">Create Event →</Link>
              </div>
            ) : (
              <div style={{ display: 'grid', gap: 16 }}>
                {events.map(ev => (
                  <div key={ev._id} className="card" style={{ padding: 20, borderLeft: `3px solid ${EVENT_STATUS_COLOR[ev.status] || '#333'}` }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 8, flexWrap: 'wrap', gap: 8 }}>
                      <div style={{ fontWeight: 600, fontSize: '1rem' }}>{ev.title}</div>
                      <span style={{ background: `${EVENT_STATUS_COLOR[ev.status]}22`, color: EVENT_STATUS_COLOR[ev.status], border: `1px solid ${EVENT_STATUS_COLOR[ev.status]}44`, borderRadius: 100, padding: '3px 10px', fontSize: '0.72rem', fontWeight: 600 }}>
                        {EVENT_STATUS_LABEL[ev.status] || ev.status}
                      </span>
                    </div>
                    <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                      {new Date(ev.startDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })} · {ev.participants?.length || 0} participants
                    </div>
                    {ev.description && (
                      <p style={{ color: 'var(--text-secondary)', fontSize: '0.85rem', marginTop: 8, marginBottom: 0 }}>
                        {ev.description.substring(0, 120)}...
                      </p>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* ── Community Profile Tab ── */}
        {activeTab === 'community' && (
          <div style={{ maxWidth: 800 }}>

            {/* Status banner */}
            {community?.status !== 'approved' && (
              <div style={{ marginBottom: 24, borderRadius: 'var(--radius-md)', padding: '16px 20px', display: 'flex', alignItems: 'center', gap: 12, background: community?.status === 'pending' ? 'rgba(245,158,11,0.1)' : 'rgba(239,68,68,0.1)', borderLeft: `4px solid ${community?.status === 'pending' ? 'var(--warning)' : '#ef4444'}` }}>
                <span style={{ fontSize: '1.5rem' }}>{community?.status === 'pending' ? '⏳' : '❌'}</span>
                <div>
                  <strong>{community?.status === 'pending' ? 'Pending Approval' : 'Community Rejected'}</strong>
                  <p style={{ margin: '4px 0 0', fontSize: '0.875rem' }}>
                    {community?.status === 'pending' ? 'Your community is awaiting System Admin approval. You can still edit your profile while waiting.' : 'Your community was rejected. Please contact the system administrator for more information.'}
                  </p>
                </div>
              </div>
            )}

            <div className="card" style={{ padding: 0, borderRadius: 'var(--radius-lg)', overflow: 'hidden', background: 'var(--bg-secondary)', border: '1px solid rgba(255,255,255,0.05)' }}>

              {/* Cover image */}
              <div>
                {form.coverImage ? (
                  <div style={{ height: 180, backgroundImage: `url(${form.coverImage})`, backgroundSize: 'cover', backgroundPosition: 'center', position: 'relative' }}>
                    <div style={{ position: 'absolute', bottom: 12, right: 16, background: 'rgba(0,0,0,0.6)', padding: '3px 10px', borderRadius: 6, fontSize: '0.72rem' }}>Cover Image</div>
                  </div>
                ) : (
                  <div style={{ height: 180, background: 'linear-gradient(135deg, var(--purple-primary), var(--cyan-accent), var(--pink-accent))', position: 'relative' }}>
                    <div style={{ position: 'absolute', bottom: 12, right: 16, background: 'rgba(0,0,0,0.5)', padding: '3px 10px', borderRadius: 6, fontSize: '0.72rem' }}>No Cover Image</div>
                  </div>
                )}

                {/* Avatar + name */}
                <div style={{ padding: '0 32px 24px', marginTop: -60, position: 'relative' }}>
                  <div style={{ display: 'flex', alignItems: 'flex-end', gap: 20, flexWrap: 'wrap' }}>
                    <div style={{ width: 110, height: 110, borderRadius: 'var(--radius-lg)', border: '4px solid var(--bg-secondary)', background: form.logo ? `url(${form.logo}) center/cover` : 'linear-gradient(135deg, var(--purple-primary), var(--cyan-accent))', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '2.5rem', boxShadow: '0 8px 24px rgba(0,0,0,0.3)', flexShrink: 0 }}>
                      {!form.logo && form.name?.charAt(0)}
                    </div>
                    <div style={{ flex: 1, marginBottom: 8 }}>
                      <div style={{ fontFamily: 'var(--font-display)', fontSize: '1.8rem', fontWeight: 'bold', marginBottom: 10 }}>
                        {form.name || 'Community Name'}
                      </div>
                      <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap' }}>
                        <span style={{ background: community?.status === 'approved' ? 'linear-gradient(135deg, #10b981, #059669)' : community?.status === 'pending' ? 'linear-gradient(135deg, var(--warning), #f59e0b)' : 'linear-gradient(135deg, #ef4444, #dc2626)', padding: '5px 12px', borderRadius: 100, fontSize: '0.75rem', fontWeight: 600, color: 'white' }}>
                          {community?.status === 'approved' ? '✓ Approved' : community?.status === 'pending' ? '⏳ Pending' : '✗ Rejected'}
                        </span>
                        <span style={{ background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))', padding: '5px 12px', borderRadius: 100, fontSize: '0.75rem', fontWeight: 600, color: 'white' }}>
                          {getCategoryIcon(form.category)} {form.category}
                        </span>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Edit / Preview sub-tabs */}
              <div style={{ borderBottom: '1px solid rgba(255,255,255,0.1)', padding: '0 32px', display: 'flex', gap: 32 }}>
                {[{ id: 'edit', label: 'Edit Profile', icon: '✏️' }, { id: 'preview', label: 'Preview', icon: '👁️' }].map(t => (
                  <button key={t.id} onClick={() => setProfileTab(t.id)} style={{ padding: '12px 0', background: 'none', border: 'none', color: profileTab === t.id ? 'var(--purple-light)' : 'var(--text-muted)', cursor: 'pointer', fontSize: '0.9rem', fontWeight: profileTab === t.id ? 600 : 400, borderBottom: profileTab === t.id ? '2px solid var(--purple-light)' : '2px solid transparent', transition: 'all 0.2s', display: 'flex', alignItems: 'center', gap: 8 }}>
                    <span>{t.icon}</span> {t.label}
                  </button>
                ))}
              </div>

              {/* Form */}
              <div style={{ padding: 32 }}>
                {profileTab === 'edit' ? (
                  <form onSubmit={handleSave}>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20, marginBottom: 20 }}>
                      <div className="form-group">
                        <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}><span>🏷️</span> Community Name *</label>
                        <input className="form-control" value={form.name || ''} onChange={e => set('name', e.target.value)} required style={{ padding: 12 }} placeholder="Enter community name" />
                      </div>
                      <div className="form-group">
                        <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}><span>📂</span> Category *</label>
                        <select className="form-control" value={form.category || ''} onChange={e => set('category', e.target.value)} style={{ padding: 12 }}>
                          {CATEGORIES.map(c => <option key={c} value={c}>{getCategoryIcon(c)} {c}</option>)}
                        </select>
                      </div>
                    </div>

                    <div className="form-group" style={{ marginBottom: 20 }}>
                      <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}><span>📝</span> Description *</label>
                      <textarea className="form-control" rows={5} value={form.description || ''} onChange={e => set('description', e.target.value)} required style={{ resize: 'vertical', padding: 12, lineHeight: 1.6 }} placeholder="Describe your community's purpose, activities, and goals..." />
                    </div>

                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20, marginBottom: 20 }}>
                      <div className="form-group">
                        <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}><span>🖼️</span> Logo URL</label>
                        <input className="form-control" value={form.logo || ''} onChange={e => set('logo', e.target.value)} placeholder="https://..." style={{ padding: 12 }} />
                      </div>
                      <div className="form-group">
                        <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}><span>🎨</span> Cover Image URL</label>
                        <input className="form-control" value={form.coverImage || ''} onChange={e => set('coverImage', e.target.value)} placeholder="https://..." style={{ padding: 12 }} />
                      </div>
                    </div>

                    <div style={{ marginBottom: 28 }}>
                      <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 12 }}><span>🔗</span> Social Links</label>
                      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: 12 }}>
                        {[
                          { key: 'website', label: '🌐 Website', placeholder: 'https://...' },
                          { key: 'facebook', label: '📘 Facebook', placeholder: 'https://facebook.com/...' },
                          { key: 'instagram', label: '📷 Instagram', placeholder: 'https://instagram.com/...' },
                          { key: 'twitter', label: '🐦 Twitter', placeholder: 'https://twitter.com/...' },
                        ].map(s => (
                          <div key={s.key}>
                            <label className="form-label" style={{ fontSize: '0.75rem' }}>{s.label}</label>
                            <input className="form-control" value={form.socialLinks?.[s.key] || ''} onChange={e => setSocial(s.key, e.target.value)} placeholder={s.placeholder} style={{ padding: 10, fontSize: '0.85rem' }} />
                          </div>
                        ))}
                      </div>
                    </div>

                    <button type="submit" className="btn btn-primary" disabled={saving} style={{ width: '100%', justifyContent: 'center', padding: 14, fontSize: '1rem', fontWeight: 600, background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))' }}>
                      {saving ? (
                        <span style={{ display: 'flex', alignItems: 'center', gap: 8 }}><span className="spinner" style={{ width: 16, height: 16, borderWidth: 2 }} /> Saving...</span>
                      ) : (
                        <span style={{ display: 'flex', alignItems: 'center', gap: 8 }}>💾 Save Profile Changes</span>
                      )}
                    </button>
                  </form>
                ) : (
                  <div style={{ padding: 20, background: 'var(--bg-elevated)', borderRadius: 'var(--radius-md)' }}>
                    <h4 style={{ marginBottom: 16, color: 'var(--purple-light)' }}>Community Preview</h4>
                    <div style={{ background: 'var(--bg-primary)', padding: 20, borderRadius: 'var(--radius-md)', border: '1px solid rgba(255,255,255,0.1)' }}>
                      {[
                        { label: 'Name', value: form.name || 'Not set' },
                        { label: 'Category', value: form.category ? `${getCategoryIcon(form.category)} ${form.category}` : 'Not set' },
                      ].map(row => (
                        <div key={row.label} style={{ marginBottom: 16 }}>
                          <strong style={{ color: 'var(--purple-light)' }}>{row.label}:</strong> {row.value}
                        </div>
                      ))}
                      <div style={{ marginBottom: 16 }}>
                        <strong style={{ color: 'var(--purple-light)' }}>Description:</strong>
                        <p style={{ marginTop: 8, color: 'var(--text-secondary)' }}>{form.description || 'No description provided'}</p>
                      </div>
                      {Object.keys(form.socialLinks || {}).filter(k => form.socialLinks[k]).length > 0 && (
                        <div>
                          <strong style={{ color: 'var(--purple-light)' }}>Social Links:</strong>
                          <div style={{ marginTop: 8, display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                            {Object.entries(form.socialLinks).map(([k, v]) => v && (
                              <a key={k} href={v} target="_blank" rel="noopener noreferrer" style={{ color: 'var(--cyan-accent)', textDecoration: 'none', fontSize: '0.85rem' }}>{k} →</a>
                            ))}
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                )}
              </div>
            </div>

            {/* Stats */}
            <div className="card" style={{ padding: 24, marginTop: 24 }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 20 }}>
                <span style={{ fontSize: '1.5rem' }}>📊</span>
                <h4 style={{ fontFamily: 'var(--font-display)', margin: 0, fontSize: '1.1rem' }}>COMMUNITY STATISTICS</h4>
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: 16 }}>
                {[
                  { label: 'Total Members', value: community?.members?.length || 0, icon: '👥', color: 'var(--purple-light)' },
                  { label: 'Total Events', value: events.length, icon: '📅', color: 'var(--cyan-accent)' },
                  { label: 'Created', value: new Date(community?.createdAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }), icon: '🎂', color: 'var(--pink-accent)' },
                  { label: 'Status', value: community?.status === 'approved' ? 'Active' : community?.status === 'pending' ? 'Pending' : 'Rejected', icon: '⚡', color: community?.status === 'approved' ? '#10b981' : 'var(--warning)' },
                ].map((s, i) => (
                  <div key={i} style={{ textAlign: 'center', padding: 20, background: 'var(--bg-elevated)', borderRadius: 'var(--radius-md)' }}>
                    <div style={{ fontSize: '2rem', marginBottom: 8 }}>{s.icon}</div>
                    <div style={{ fontFamily: 'var(--font-display)', fontSize: '1.5rem', color: s.color, fontWeight: 'bold' }}>{s.value}</div>
                    <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginTop: 8 }}>{s.label}</div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

      </div>
    </div>
  );
}
